#!/usr/bin/env python3
"""
Blog content audit batch 5: Process Bangla blog posts 31-45.
Expands each post to 2000+ words with AEO/GEO/EEAT/FAQ/internal links.
"""
import re, os

DATA_FILE = os.path.join(os.path.dirname(os.path.dirname(__file__)),
                         'src/app/blog/data.js')

def read_posts():
    with open(DATA_FILE, 'r', encoding='utf-8') as f:
        return f.read()

def write_posts(content):
    with open(DATA_FILE, 'w', encoding='utf-8') as f:
        f.write(content)

def extract_post(content, slug):
    slug_match = re.search(r'slug:\s*"' + re.escape(slug) + '"', content)
    if not slug_match:
        return None, None, None
    from_slug = content[slug_match.start():]
    content_marker = re.search(r'content:\s*`\n?', from_slug)
    if not content_marker:
        return None, None, None
    content_start = slug_match.start() + content_marker.end()
    rest = content[content_start:]
    close_match = re.search(r'\n\s*`\s*,\s*\n\s*\},\s*', rest)
    if not close_match:
        return None, None, None
    content_end = content_start + close_match.start()
    existing_content = content[content_start:content_end]
    # prefix: from opening { to after content: `
    pre_slug = content[:slug_match.start()]
    last_open_brace = pre_slug.rfind('{')
    prefix_end = slug_match.start() + content_marker.end()
    prefix_full = content[last_open_brace:prefix_end]
    return None, prefix_full, existing_content

def wc(text):
    return len(text.split())

